/**
 * DataTable — Generated by Elmoorx AI Copilot
 */
import { $store, h } from "@elmoorx/runtime";

const DataTable = () => {
  const store = $store({
    rows: [
      { id: 1, name: "Alice", email: "alice@ex.com", role: "Admin" },
      { id: 2, name: "Bob", email: "bob@ex.com", role: "User" },
    ],
    sortKey: null,
    sortDir: "asc",
  });

  const sortBy = (key) => {
    if (store.sortKey === key) {
      store.sortDir = store.sortDir === "asc" ? "desc" : "asc";
    } else {
      store.sortKey = key;
      store.sortDir = "asc";
    }
  };

  const sorted = () => {
    if (!store.sortKey) return store.rows;
    const key = store.sortKey;
    const dir = store.sortDir === "asc" ? 1 : -1;
    return [...store.rows].sort((a, b) => a[key] < b[key] ? -dir : a[key] > b[key] ? dir : 0);
  };

  return h("table", null,
    h("thead", null,
      h("tr", null,
        ["id", "name", "email", "role"].map(k =>
          h("th", { onClick: () => sortBy(k) }, k))
      )
    ),
    h("tbody", null,
      () => sorted().map(row =>
        h("tr", null,
          h("td", null, String(row.id)),
          h("td", null, row.name),
          h("td", null, row.email),
          h("td", null, row.role)
        )
      )
    )
  );
};

export default function Page() {
  return h("main", null, DataTable());
}
